-- mod-item-talents ФАЗА 2: спеллы ряда 5 "Пробуждение" (spell_dbc).
-- Канон id: .claude/item-talents/CUSTOM_SPELLS.md (диапазон 108000-108099
-- проверен свободным, занят только 108500 env-effects).
--   108000-108042 - СКРЫТЫЕ триггер-пассивы (маркеры на игроке, server-only,
--                   в клиентский MPQ НЕ идут);
--   108050-108092 - ВИДИМЫЕ спеллы эффектов (бафы/дебафы/урон/хил/призыв);
--                   SpellIconID пока 1 - клиентские иконки уедут в MPQ
--                   отдельно (Spell_custom.csv), серверу не критично.
--
-- КРИТИЧНО (грабли проекта, feedback_spell_dbc_aura_fields): у всех строк с
-- Effect=6 (APPLY_AURA) обязательны DurationIndex и ProcChance=101, у
-- постоянных скрытых аур - Attributes 0x80000000 (NO_AURA_CANCEL) +
-- 0x40 (PASSIVE) + 0x80 (DO_NOT_DISPLAY, скрытие со спеллбука/панели
-- баффов/комбат-лога) = 2147483840, плюс AttributesEx 0x10000000
-- (SPELL_ATTR1_NO_AURA_ICON) = 268435456.
--
-- DurationIndex (проверены по .claude/dbc/Spell.csv на спеллах с известной
-- длительностью, по 2-3 подтверждения на индекс):
--   39 = 2 сек (War Stomp 20549, Bash 5211)
--   35 = 4 сек (Cheap Shot 1833, Concussive Shot 5116)
--   28 = 5 сек (Spell Reflection 23920, Frost Armor chill 6136, Earthbind 3600)
--   32 = 6 сек (Hammer of Justice R4 10308, Blast Wave 11113)
--   31 = 8 сек (Frost Shock 8056, Psychic Scream 8122, Cone of Cold 120)
--   1  = 10 сек (Shield Block 2565, Blind 2094, Ice Block 45438)
--   8  = 15 сек (Sprint 2983, Adrenaline Rush 13750, Hamstring 1715)
--   21 = перманентная (конвенция проекта)
--
-- Модуль кастует видимые спеллы через CastCustomSpell с bp-override
-- (EffectDieSides 0 - значение подставляется как есть); спеллы с
-- фиксированным эффектом (скорости, стан, доп. удары) несут basepoints в dbc.
-- Аура-типы: 3 периодика, 4 дамми, 12 стан, 13/135 урон/лечение закл.,
-- 22 сопротивление (misc 1 = броня, 126 = все школы), 29 стат (misc 1 = лов.),
-- 31 скорость бега, 33 замедление, 69 поглощение, 99/124 сила атаки
-- ближняя/дальняя, 138 скорость атаки, 158 блокирование (флэт),
-- 189 рейтинги (misc: 4 уклонение, 8 парирование, 1792 крит, 917504 хейст).
-- Эффекты: 2 SCHOOL_DAMAGE, 10 HEAL, 19 ADD_EXTRA_ATTACKS, 30 ENERGIZE,
-- 68 INTERRUPT_CAST. Школы: 1 физ., 2 свет, 8 природа, 16 лед, 32 тьма,
-- 64 тайная. Mechanic: 11 замедление, 12 стан, 15 кровотечение.
--
-- spell_dbc грузится при СТАРТЕ worldserver - после применения нужен РЕСТАРТ.
-- Идемпотентно: DELETE диапазона + REPLACE INTO.

DELETE FROM `spell_dbc` WHERE `ID` BETWEEN 108000 AND 108044;
DELETE FROM `spell_dbc` WHERE `ID` BETWEEN 108050 AND 108092;

